// Simple IndexedDB wrapper
const DB_NAME = 'fsaudit-db';
const STORE = 'audits';
let db;
function openDB() {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(DB_NAME, 1);
    req.onupgradeneeded = (e) => {
      db = e.target.result;
      if (!db.objectStoreNames.contains(STORE)) {
        db.createObjectStore(STORE, { keyPath: 'id', autoIncrement: true });
      }
    };
    req.onsuccess = (e) => { db = e.target.result; resolve(db); };
    req.onerror = (e) => reject(e.target.error);
  });
}
function saveAudit(audit) {
  return new Promise((resolve, reject) => {
    const tx = db.transaction(STORE, 'readwrite');
    tx.oncomplete = () => resolve(true);
    tx.onerror = (e) => reject(e.target.error);
    tx.objectStore(STORE).put(audit);
  });
}
function listAudits() {
  return new Promise((resolve, reject) => {
    const tx = db.transaction(STORE, 'readonly');
    const store = tx.objectStore(STORE);
    const req = store.getAll();
    req.onsuccess = () => resolve(req.result.sort((a,b)=> (b.savedAt||0)-(a.savedAt||0)) );
    req.onerror = (e) => reject(e.target.error);
  });
}

// State
let currentAudit = null;
let flatQuestions = [];

function init() {
  openDB().then(() => { refreshAuditList(); renderDashboard(); });
  document.getElementById('startAuditBtn').addEventListener('click', startAudit);
  document.getElementById('saveAuditBtn').addEventListener('click', onSave);
  document.getElementById('exportBtn').addEventListener('click', onExportCSV);
  document.getElementById('printBtn').addEventListener('click', () => window.print());
  document.getElementById('navHome').addEventListener('click', ()=>showView('homeView'));
  document.getElementById('navAudit').addEventListener('click', ()=>showView('auditView'));
  document.getElementById('navDashboard').addEventListener('click', ()=>{ showView('dashboardView'); renderDashboard(); });
  document.getElementById('prevQ').addEventListener('click', ()=>navigateQ(-1));
  document.getElementById('nextQ').addEventListener('click', ()=>navigateQ(1));
  document.getElementById('questionsData').textContent = JSON.stringify(DATA, null, 2);
}

function refreshAuditList() {
  listAudits().then(items => {
    const ul = document.getElementById('auditList');
    ul.innerHTML = '';
    items.forEach(it => {
      const li = document.createElement('li');
      const meta = `${it.meta.site} — ${new Date(it.meta.date).toLocaleDateString()} (${scoreAudit(it).toFixed(0)}%)`;
      li.innerHTML = `<strong>${meta}</strong><br><span class="muted">${it.meta.location} • ${it.meta.auditor}</span>`;
      li.addEventListener('click', ()=> loadAudit(it));
      ul.appendChild(li);
    });
  });
}

function startAudit() {
  const site = document.getElementById('site').value.trim();
  const location = document.getElementById('location').value.trim();
  const auditor = document.getElementById('auditor').value.trim();
  const date = document.getElementById('auditDate').value || new Date().toISOString().slice(0,10);

  currentAudit = {
    id: Date.now(),
    meta: { site, location, auditor, date },
    data: JSON.parse(JSON.stringify(DATA.sections))
  };
  buildAuditUI();
  showView('auditView');
}

function loadAudit(a) {
  currentAudit = a;
  buildAuditUI();
  showView('auditView');
}

function buildAuditUI() {
  const cont = document.getElementById('sectionContainer');
  cont.innerHTML = '';
  flatQuestions = [];

  const metaDiv = document.getElementById('auditMeta');
  metaDiv.innerHTML = `<strong>${currentAudit.meta.site}</strong><br><span class="muted">${currentAudit.meta.location} • ${currentAudit.meta.auditor} • ${new Date(currentAudit.meta.date).toLocaleDateString()}</span><br><span class="badge">Score: ${scoreAudit(currentAudit).toFixed(0)}%</span>`;

  currentAudit.data.forEach((sec, sidx) => {
    const card = document.createElement('div');
    card.className = 'card';
    const secTitle = document.createElement('h3');
    secTitle.className = 'section-title';
    secTitle.textContent = sec.name;
    card.appendChild(secTitle);

    const ul = document.createElement('ul');
    ul.className = 'list';

    sec.questions.forEach((q, qidx) => {
      flatQuestions.push({ sidx, qidx });

      const li = document.createElement('li');
      li.innerHTML = `<div><strong>${q.text}</strong><br><small>${q.reference ? q.reference + ' • ' : ''}${q.evidence || ''}</small></div>
        <div style="margin-top:8px; display:flex; gap:6px;">
          <select data-field="rating">
            <option value="">Rating…</option>
            <option>Yes</option>
            <option>No</option>
            <option>Partial</option>
            <option>N.A.</option>
          </select>
          <select data-field="risk">
            <option value="">Risk…</option>
            <option>L</option>
            <option>M</option>
            <option>H</option>
          </select>
          <button class="btn ghost">Open</button>
        </div>`;
      const [selRating, selRisk, btnOpen] = li.querySelectorAll('select, button');
      selRating.value = q.rating || '';
      selRisk.value = q.risk || '';
      selRating.addEventListener('change', (e)=>{ q.rating = e.target.value; updateProgress(); });
      selRisk.addEventListener('change', (e)=>{ q.risk = e.target.value; });
      btnOpen.addEventListener('click', ()=> openQuestion(sidx, qidx));

      ul.appendChild(li);
    });

    card.appendChild(ul);
    cont.appendChild(card);
  });

  updateProgress();
}

function updateProgress(){
  const metaDiv = document.getElementById('auditMeta');
  if(!metaDiv) return;
  metaDiv.querySelector('.badge').textContent = `Score: ${scoreAudit(currentAudit).toFixed(0)}%`;
}

function scoreAudit(audit){
  let num=0, den=0;
  audit.data.forEach(sec=>{
    sec.questions.forEach(q=>{
      if(q.rating === 'N.A.' || q.rating === '') return;
      den++;
      if(q.rating === 'Yes') num += 1;
      else if(q.rating === 'Partial') num += 0.5;
    })
  })
  return den? (num*100/den):0;
}

function openQuestion(sidx, qidx){
  const q = currentAudit.data[sidx].questions[qidx];
  const card = document.getElementById('questionCard');
  card.innerHTML = `
    <div class="card">
      <div class="section-title">${currentAudit.data[sidx].name}</div>
      <h3>${q.text}</h3>
      <p><small>${q.reference ? q.reference + ' • ' : ''}${q.evidence || ''}</small></p>
      <label>Rating<select id="q_rating"><option value=""></option><option>Yes</option><option>No</option><option>Partial</option><option>N.A.</option></select></label>
      <label>Risk<select id="q_risk"><option value=""></option><option>L</option><option>M</option><option>H</option></select></label>
      <label>Findings / Notes<textarea id="q_findings" placeholder="Observations…"></textarea></label>
      <label>Corrective Action<textarea id="q_ca" placeholder="Action required…"></textarea></label>
      <label>Action Owner<input id="q_owner" type="text" placeholder="Responsible person"/></label>
      <label>Due Date<input id="q_due" type="date"/></label>
      <label>Status<select id="q_status"><option value=""></option><option>Open</option><option>Closed</option></select></label>
      <label>Photo / Evidence<input id="q_photo" type="file" accept="image/*;capture=camera"/></label>
    </div>`;
  card.dataset.sidx = sidx; card.dataset.qidx = qidx;
  document.getElementById('q_rating').value = q.rating || '';
  document.getElementById('q_risk').value = q.risk || '';
  document.getElementById('q_findings').value = q.findings || '';
  document.getElementById('q_ca').value = q.corrective_action || '';
  document.getElementById('q_owner').value = q.owner || '';
  if(q.due_date) document.getElementById('q_due').value = q.due_date;
  document.getElementById('q_status').value = q.status || '';

  document.getElementById('q_photo').addEventListener('change', async (e)=>{
    const file = e.target.files[0]; if(!file) return; const base64 = await fileToBase64(file); q.photo = base64;
  });

  ['q_rating','q_risk','q_findings','q_ca','q_owner','q_due','q_status'].forEach(id=>{
    document.getElementById(id).addEventListener('change', ()=>{
      q.rating = document.getElementById('q_rating').value;
      q.risk = document.getElementById('q_risk').value;
      q.findings = document.getElementById('q_findings').value;
      q.corrective_action = document.getElementById('q_ca').value;
      q.owner = document.getElementById('q_owner').value;
      q.due_date = document.getElementById('q_due').value;
      q.status = document.getElementById('q_status').value;
      updateProgress();
    });
  });

  showView('detailView');
}

function navigateQ(delta){
  const sidx = parseInt(document.getElementById('questionCard').dataset.sidx);
  const qidx = parseInt(document.getElementById('questionCard').dataset.qidx);
  if(Number.isNaN(sidx)||Number.isNaN(qidx)) return;
  if(flatQuestions.length===0) {
    currentAudit.data.forEach((sec, s)=> sec.questions.forEach((q, qx)=> flatQuestions.push({sidx:s, qidx: qx})));
  }
  const flatIndex = flatQuestions.findIndex(x=>x.sidx===sidx && x.qidx===qidx);
  const next = Math.min(Math.max(flatIndex + delta, 0), flatQuestions.length-1);
  openQuestion(flatQuestions[next].sidx, flatQuestions[next].qidx);
}

function onSave(){
  currentAudit.savedAt = Date.now();
  saveAudit(currentAudit).then(()=>{ alert('Saved'); refreshAuditList(); renderDashboard(); });
}

function onExportCSV(){
  const rows = [];
  const meta = currentAudit.meta;
  currentAudit.data.forEach(sec=>{
    sec.questions.forEach(q=>{
      rows.push({
        Site: meta.site,
        Location: meta.location,
        Auditor: meta.auditor,
        Date: meta.date,
        Section: sec.name,
        Question: q.text,
        Reference: q.reference,
        Evidence: q.evidence,
        Rating: q.rating,
        Risk: q.risk,
        Findings: q.findings,
        Corrective_Action: q.corrective_action,
        Owner: q.owner,
        Due_Date: q.due_date,
        Status: q.status
      })
    })
  });
  const csv = toCSV(rows);
  downloadFile(csv, `FireSafetyAudit_${Date.now()}.csv`, 'text/csv');
}

function toCSV(arr){ if(arr.length===0) return ''; const headers = Object.keys(arr[0]); const escape = (v)=>'"'+String(v||'').replace(/"/g,'""')+'"'; const lines=[headers.join(',')]; arr.forEach(o=> lines.push(headers.map(h=>escape(o[h])).join(','))); return lines.join('\n'); }
function downloadFile(content, filename, mime){ const blob = new Blob([content], {type:mime}); const url = URL.createObjectURL(blob); const a = document.createElement('a'); a.href = url; a.download = filename; a.click(); setTimeout(()=> URL.revokeObjectURL(url), 1000); }
function showView(id){ document.querySelectorAll('.view').forEach(v=> v.classList.add('hidden')); document.getElementById(id).classList.remove('hidden'); }
function fileToBase64(file){ return new Promise((resolve,reject)=>{ const reader = new FileReader(); reader.onload = ()=> resolve(reader.result); reader.onerror = reject; reader.readAsDataURL(file); }); }

// === Dashboard ===
